29	  func standardUserDriverWillHandleShowingUpdate(_ handleShowingUpdate: Bool, forUpdate update: SUAppcastItem, state: SPUUserUpdateState) {
30	    NSApp.setActivationPolicy(.regular)
31	    if !state.userInitiated {
32	      NSApp.dockTile.badgeLabel = "1"
33	      let content = UNMutableNotificationContent()
34	      content.title = NSLocalizedString("A new update is available", comment: "Update")
35	      content.body = NSLocalizedString("Version [version] is now available", comment: "Update").replacingOccurrences(of: "[version]", with: update.displayVersionString)
36	      let request = UNNotificationRequest(identifier: Self.updateNotificationIdentifier, content: content, trigger: nil)
37	      UNUserNotificationCenter.current().add(request)
38	    }
39	  }
40	
41	  func standardUserDriverDidReceiveUserAttention(forUpdate update: SUAppcastItem) {
42	    NSApp.dockTile.badgeLabel = ""
43	    UNUserNotificationCenter.current().removeDeliveredNotifications(withIdentifiers: [Self.updateNotificationIdentifier])
44	  }
45	
46	  func standardUserDriverWillFinishUpdateSession() {
47	    NSApp.setActivationPolicy(.accessory)
48	  }
49	
50	  func userNotificationCenter(_ center: UNUserNotificationCenter, didReceive response: UNNotificationResponse, withCompletionHandler completionHandler: @escaping () -> Void) {
51	    if response.notification.request.identifier == Self.updateNotificationIdentifier && response.actionIdentifier == UNNotificationDefaultActionIdentifier {
52	      updateController.updater.checkForUpdates()
53	    }
54	
55	    completionHandler()
56	  }
