1	//
2	//  SquirrelInputController.swift
3	//  Squirrel
4	//
5	//  Created by Leo Liu on 5/7/24.
6	//
7	
8	import InputMethodKit
9	
10	final class SquirrelInputController: IMKInputController {
11	  private static let keyRollOver = 50
12	  private static var unknownAppCnt: UInt = 0
13	
14	  private weak var client: IMKTextInput?
15	  private let rimeAPI: RimeApi_stdbool = rime_get_api_stdbool().pointee
16	  private var preedit: String = ""
17	  private var selRange: NSRange = .empty
18	  private var caretPos: Int = 0
19	  private var lastModifiers: NSEvent.ModifierFlags = .init()
20	  private var session: RimeSessionId = 0
21	  private var schemaId: String = ""
22	  private var inlinePreedit = false
23	  private var inlineCandidate = false
24	  private var chordKeyCodes: [UInt32] = .init(repeating: 0, count: SquirrelInputController.keyRollOver)
25	  private var chordModifiers: [UInt32] = .init(repeating: 0, count: SquirrelInputController.keyRollOver)
26	  private var chordKeyCount: Int = 0
27	  private var chordTimer: Timer?
28	  private var chordDuration: TimeInterval = 0
29	  private var currentApp: String = ""
30	
31	  // swiftlint:disable:next cyclomatic_complexity
32	  override func handle(_ event: NSEvent!, client sender: Any!) -> Bool {
33	    guard let event = event else { return false }
34	    let modifiers = event.modifierFlags
35	    let changes = lastModifiers.symmetricDifference(modifiers)
36	
37	    // Return true to consume the key event; return false to pass it to the client app.
38	    var handled = false
39	
40	    if session == 0 || !rimeAPI.find_session(session) {
41	      createSession()
42	      if session == 0 {
43	        return false
44	      }
45	    }
46	
47	    self.client ?= sender as? IMKTextInput
48	    if let app = client?.bundleIdentifier(), currentApp != app {
49	      currentApp = app
50	      updateAppOptions()
51	    }
52	
53	    switch event.type {
54	    case .flagsChanged:
55	      if lastModifiers == modifiers {
56	        handled = true
57	        break
58	      }
59	      var rimeModifiers: UInt32 = SquirrelKeycode.osxModifiersToRime(modifiers: modifiers)
60	      // Some remote desktop tools send flagsChanged with keyCode 0; infer the real modifier key when needed.
61	      var keyCode = event.keyCode
62	      if !SquirrelKeycode.modifierKeycodes.contains(keyCode) {
63	        guard let inferred = SquirrelKeycode.inferModifierKeycode(from: changes) else {
64	          lastModifiers = modifiers
65	          rimeUpdate()
66	          handled = true
67	          break
68	        }
69	        keyCode = inferred
70	      }
71	      let rimeKeycode: UInt32 = SquirrelKeycode.osxKeycodeToRime(keycode: keyCode, keychar: nil, shift: false, caps: false)
72	
73	      if changes.contains(.capsLock) {
74	        // Rime expects XK_Caps_Lock before the lock mask changes; NSFlagsChanged has already applied it.
75	        rimeModifiers ^= kLockMask.rawValue
76	        _ = processKey(rimeKeycode, modifiers: rimeModifiers)
77	      }
78	
79	      // Process releases first because some modifier releases arrive with the next keydown.
80	      var buffer = [(keycode: UInt32, modifier: UInt32)]()
81	      for flag in [NSEvent.ModifierFlags.shift, .control, .option, .command] where changes.contains(flag) {
82	        if modifiers.contains(flag) {
83	          buffer.append((keycode: rimeKeycode, modifier: rimeModifiers))
84	        } else {
85	          buffer.insert((keycode: rimeKeycode, modifier: rimeModifiers | kReleaseMask.rawValue), at: 0)
86	        }
87	      }
88	      for (keycode, modifier) in buffer {
89	        _ = processKey(keycode, modifiers: modifier)
90	      }
91	
92	      lastModifiers = modifiers
93	      rimeUpdate()
94	
95	    case .keyDown:
96	      // Let client apps handle Command shortcuts.
97	      if modifiers.contains(.command) {
98	        break
99	      }
100	
101	      let keyCode = event.keyCode
102	      var keyChars = event.charactersIgnoringModifiers
103	      let capitalModifiers = modifiers.isSubset(of: [.shift, .capsLock])
104	      if let code = keyChars?.first,
105	         (capitalModifiers && !code.isLetter) || (!capitalModifiers && !code.isASCII) {
106	        keyChars = event.characters
107	      }
108	      if let char = keyChars?.first {
109	        let rimeKeycode = SquirrelKeycode.osxKeycodeToRime(keycode: keyCode, keychar: char,
110	                                                           shift: modifiers.contains(.shift),
111	                                                           caps: modifiers.contains(.capsLock))
112	        if rimeKeycode != 0 {
113	          let rimeModifiers = SquirrelKeycode.osxModifiersToRime(modifiers: modifiers)
114	          handled = processKey(rimeKeycode, modifiers: rimeModifiers)
115	          rimeUpdate()
116	        }
117	      }
118	
119	    default:
120	      break
121	    }
122	
123	    return handled
124	  }
125	
126	  func selectCandidate(_ index: Int) -> Bool {
127	    let success = rimeAPI.select_candidate_on_current_page(session, index)
128	    if success {
129	      rimeUpdate()
130	    }
131	    return success
132	  }
133	
134	  // swiftlint:disable:next identifier_name
135	  func page(up: Bool) -> Bool {
136	    var handled = false
137	    handled = rimeAPI.change_page(session, up)
138	    if handled {
139	      rimeUpdate()
140	    }
141	    return handled
142	  }
143	
144	  func moveCaret(forward: Bool) -> Bool {
145	    let currentCaretPos = rimeAPI.get_caret_pos(session)
146	    guard let input = rimeAPI.get_input(session) else { return false }
147	    if forward {
148	      if currentCaretPos <= 0 {
149	        return false
150	      }
151	      rimeAPI.set_caret_pos(session, currentCaretPos - 1)
152	    } else {
153	      let inputStr = String(cString: input)
154	      if currentCaretPos >= inputStr.utf8.count {
155	        return false
156	      }
157	      rimeAPI.set_caret_pos(session, currentCaretPos + 1)
158	    }
159	    rimeUpdate()
160	    return true
161	  }
162	
163	  override func recognizedEvents(_ sender: Any!) -> Int {
164	    return Int(NSEvent.EventTypeMask.Element(arrayLiteral: .keyDown, .flagsChanged).rawValue)
165	  }
166	
167	  override func activateServer(_ sender: Any!) {
168	    self.client ?= sender as? IMKTextInput
169	    var keyboardLayout = NSApp.squirrelAppDelegate.config?.getString("keyboard_layout") ?? ""
170	    if keyboardLayout == "last" || keyboardLayout == "" {
171	      keyboardLayout = ""
172	    } else if keyboardLayout == "default" {
173	      keyboardLayout = "com.apple.keylayout.ABC"
174	    } else if !keyboardLayout.hasPrefix("com.apple.keylayout.") {
175	      keyboardLayout = "com.apple.keylayout.\(keyboardLayout)"
176	    }
177	    if keyboardLayout != "" {
178	      client?.overrideKeyboard(withKeyboardNamed: keyboardLayout)
179	    }
180	    preedit = ""
181	    if session != 0 {
182	      let state = rimeAPI.get_option(session, "ascii_mode")
183	      let label = rimeAPI.get_state_label_abbreviated(session, "ascii_mode", state, true).asString
184	      NSApp.squirrelAppDelegate.updateStatusIcon(asciiMode: state, schemaLabel: label)
185	    }
186	  }
187	
188	  override init!(server: IMKServer!, delegate: Any!, client: Any!) {
189	    self.client = client as? IMKTextInput
190	    super.init(server: server, delegate: delegate, client: client)
191	    createSession()
192	
193	    NotificationCenter.default.addObserver(
194	      forName: .init("SquirrelSetASCIIModeNotification"),
195	      object: nil,
196	      queue: nil
197	    ) { [weak self] notification in
198	      self?.handleASCIIModeToggle(notification)
199	    }
200	
201	    NotificationCenter.default.addObserver(
202	      forName: .init("SquirrelReportASCIIModeNotification"),
203	      object: nil,
204	      queue: nil
205	    ) { [weak self] notification in
206	      self?.reportASCIIMode(notification)
207	    }
208	  }
209	
210	  override func deactivateServer(_ sender: Any!) {
211	    hidePalettes()
212	    commitComposition(sender)
213	    client = nil
214	  }
215	
216	  override func hidePalettes() {
217	    NSApp.squirrelAppDelegate.panel?.hide()
218	    super.hidePalettes()
219	  }
220	
221	  override func commitComposition(_ sender: Any!) {
222	    self.client ?= sender as? IMKTextInput
223	    if session != 0 {
224	      if let input = rimeAPI.get_input(session) {
