302	private extension SquirrelInputController {
303	
304	  func onChordTimer(_: Timer) {
305	    var processedKeys = false
306	    if chordKeyCount > 0 && session != 0 {
307	      // Chord typing releases are synthesized after the configured timeout.
308	      for i in 0..<chordKeyCount {
309	        let handled = rimeAPI.process_key(session, Int32(chordKeyCodes[i]), Int32(chordModifiers[i] | kReleaseMask.rawValue))
310	        if handled {
311	          processedKeys = true
312	        }
313	      }
314	    }
315	    clearChord()
316	    if processedKeys {
317	      rimeUpdate()
318	    }
319	  }
320	
321	  func updateChord(keycode: UInt32, modifiers: UInt32) {
322	    for i in 0..<chordKeyCount where chordKeyCodes[i] == keycode {
323	      return
324	    }
325	    if chordKeyCount >= Self.keyRollOver {
326	      return
327	    }
328	    chordKeyCodes[chordKeyCount] = keycode
329	    chordModifiers[chordKeyCount] = modifiers
330	    chordKeyCount += 1
331	    if let timer = chordTimer, timer.isValid {
332	      timer.invalidate()
333	    }
334	    chordDuration = 0.1
335	    if let duration = NSApp.squirrelAppDelegate.config?.getDouble("chord_duration"), duration > 0 {
336	      chordDuration = duration
337	    }
338	    chordTimer = Timer.scheduledTimer(withTimeInterval: chordDuration, repeats: false, block: onChordTimer)
339	  }
340	
341	  func clearChord() {
342	    chordKeyCount = 0
343	    if let timer = chordTimer {
344	      if timer.isValid {
345	        timer.invalidate()
346	      }
347	      chordTimer = nil
348	    }
349	  }
350	
351	  func createSession() {
352	    let app = client?.bundleIdentifier() ?? {
353	      SquirrelInputController.unknownAppCnt &+= 1
354	      return "UnknownApp\(SquirrelInputController.unknownAppCnt)"
355	    }()
356	    print("createSession: \(app)")
357	    currentApp = app
358	    session = rimeAPI.create_session()
359	    schemaId = ""
360	
361	    if session != 0 {
362	      updateAppOptions()
363	    }
364	  }
365	
366	  func updateAppOptions() {
367	    if currentApp == "" {
368	      return
369	    }
370	    if let appOptions = NSApp.squirrelAppDelegate.config?.getAppOptions(currentApp) {
371	      for (key, value) in appOptions {
372	        print("set app option: \(key) = \(value)")
373	        rimeAPI.set_option(session, key, value)
374	      }
375	    }
376	    if let reportBundleID = NSApp.squirrelAppDelegate.config?.getBool("unsafe/report_bundleid"), reportBundleID {
377	      currentApp.withCString { name in
378	        rimeAPI.set_property(session, "client_app", name)
379	      }
380	    }
381	  }
382	
383	  func destroySession() {
384	    if session != 0 {
385	      _ = rimeAPI.destroy_session(session)
386	      session = 0
387	    }
388	    clearChord()
389	  }
390	
391	  func processKey(_ rimeKeycode: UInt32, modifiers rimeModifiers: UInt32) -> Bool {
392	    if let panel = NSApp.squirrelAppDelegate.panel {
393	      if panel.linear != rimeAPI.get_option(session, "_linear") {
394	        rimeAPI.set_option(session, "_linear", panel.linear)
395	      }
396	      if panel.vertical != rimeAPI.get_option(session, "_vertical") {
397	        rimeAPI.set_option(session, "_vertical", panel.vertical)
398	      }
399	    }
400	
401	    let handled = rimeAPI.process_key(session, Int32(rimeKeycode), Int32(rimeModifiers))
402	
403	    if !handled {
404	      let isVimBackInCommandMode = rimeKeycode == XK_Escape || ((rimeModifiers & kControlMask.rawValue != 0) && (rimeKeycode == XK_c || rimeKeycode == XK_C || rimeKeycode == XK_bracketleft))
405	      if isVimBackInCommandMode && rimeAPI.get_option(session, "vim_mode") &&
406	          !rimeAPI.get_option(session, "ascii_mode") {
407	        rimeAPI.set_option(session, "ascii_mode", true)
408	      }
409	    } else {
410	      let isChordingKey = switch Int32(rimeKeycode) {
411	      case XK_space...XK_asciitilde, XK_Control_L, XK_Control_R, XK_Alt_L, XK_Alt_R, XK_Shift_L, XK_Shift_R:
412	        true
413	      default:
414	        false
415	      }
416	      if isChordingKey && rimeAPI.get_option(session, "_chord_typing") {
417	        updateChord(keycode: rimeKeycode, modifiers: rimeModifiers)
418	      } else if (rimeModifiers & kReleaseMask.rawValue) == 0 {
419	        clearChord()
420	      }
421	    }
422	
423	    return handled
424	  }
425	
426	  func rimeConsumeCommittedText() {
427	    var commitText = RimeCommit.rimeStructInit()
428	    if rimeAPI.get_commit(session, &commitText) {
429	      if let text = commitText.text {
430	        commit(string: String(cString: text))
431	      }
432	      _ = rimeAPI.free_commit(&commitText)
433	    }
434	  }
435	
436	  // Preserve reserved comment marks when librime requests a UI-only refresh.
437	  func rimeUpdate(clearReservedComments: Bool = true) {
438	    if clearReservedComments {
439	      specialCommentIndices = [:]
440	    }
441	    rimeConsumeCommittedText()
442	
443	    var status = RimeStatus_stdbool.rimeStructInit()
444	    if rimeAPI.get_status(session, &status) {
445	      // swiftlint:disable:next identifier_name
446	      if let schema_id = status.schema_id, schemaId == "" || schemaId != String(cString: schema_id) {
447	        schemaId = String(cString: schema_id)
448	        NSApp.squirrelAppDelegate.loadSettings(for: schemaId)
449	        if let panel = NSApp.squirrelAppDelegate.panel {
450	          inlinePreedit = (panel.inlinePreedit && !rimeAPI.get_option(session, "no_inline")) || rimeAPI.get_option(session, "inline")
451	          inlineCandidate = panel.inlineCandidate && !rimeAPI.get_option(session, "no_inline")
452	          rimeAPI.set_option(session, "soft_cursor", !inlinePreedit)
453	        }
454	      }
455	      _ = rimeAPI.free_status(&status)
456	    }
457	
458	    var ctx = RimeContext_stdbool.rimeStructInit()
459	    if rimeAPI.get_context(session, &ctx) {
460	      let preedit = ctx.composition.preedit.map({ String(cString: $0) }) ?? ""
461	
462	      let start = String.Index(preedit.utf8.index(preedit.utf8.startIndex, offsetBy: Int(ctx.composition.sel_start)), within: preedit) ?? preedit.startIndex
463	      let end = String.Index(preedit.utf8.index(preedit.utf8.startIndex, offsetBy: Int(ctx.composition.sel_end)), within: preedit) ?? preedit.startIndex
464	      let caretPos = String.Index(preedit.utf8.index(preedit.utf8.startIndex, offsetBy: Int(ctx.composition.cursor_pos)), within: preedit) ?? preedit.startIndex
465	
466	      if inlineCandidate {
467	        var candidatePreview = ctx.commit_text_preview.map { String(cString: $0) } ?? ""
468	        let endOfCandidatePreview = candidatePreview.endIndex
469	        if inlinePreedit {
470	          // 左移光標後的情形：
471	          // preedit:             ^已選某些字[xiang zuo yi dong]|guangbiao$
472	          // commit_text_preview: ^已選某些字向左移動$
473	          // candidate_preview:   ^已選某些字[向左移動]|guangbiao$
474	          // 繼續翻頁至指定更短字詞的情形：
475	          // preedit:             ^已選某些字[xiang zuo]yidong|guangbiao$
476	          // commit_text_preview: ^已選某些字向左yidong$
477	          // candidate_preview:   ^已選某些字[向左]yidong|guangbiao$
478	          // 光標移至當前段落最左端的情形：
479	          // preedit:             ^已選某些字|[xiang zuo yi dong guang biao]$
480	          // commit_text_preview: ^已選某些字向左移動光標$
481	          // candidate_preview:   ^已選某些字|[向左移動光標]$
482	          // 討論：
483	          // preedit 與 commit_text_preview 中“已選某些字”部分一致
484	          // 因此，選中範圍即正在翻譯的碼段“向左移動”中，兩者的 start 值一致
485	          // 光標位置的範圍是 start ..= endOfCandidatePreview
486	          if caretPos >= end && caretPos < preedit.endIndex {
487	            // 從 preedit 截取光標後未翻譯的編碼“guangbiao”
488	            candidatePreview += preedit[caretPos...]
489	          }
490	        } else {
491	          // 翻頁至指定更短字詞的情形：
492	          // preedit:             ^已選某些字[xiang zuo]yidong|guangbiao$
493	          // commit_text_preview: ^已選某些字向左yidongguangbiao$
494	          // candidate_preview:   ^已選某些字[向左???]|$
495	          // 光標移至當前段落最左端，繼續翻頁至指定更短字詞的情形：
496	          // preedit:             ^已選某些字|[xiang zuo]yidongguangbiao$
497	          // commit_text_preview: ^已選某些字向左yidongguangbiao$
498	          // candidate_preview:   ^已選某些字|[向左]???$
499	          // FIXME: add librime APIs to support preview candidate without remaining code.
500	        }
501	        // preedit can contain additional prompt text before start:
502	        // ^(prompt)[selection]$
503	        let start = min(start, candidatePreview.endIndex)
504	        let caretPos = caretPos <= start ? caretPos : endOfCandidatePreview
505	        show(preedit: candidatePreview,
506	             selRange: NSRange(location: start.utf16Offset(in: candidatePreview),
507	                               length: candidatePreview.utf16.distance(from: start, to: candidatePreview.endIndex)),
508	             caretPos: caretPos.utf16Offset(in: candidatePreview))
509	      } else {
510	        if inlinePreedit {
511	          show(preedit: preedit, selRange: NSRange(location: start.utf16Offset(in: preedit), length: preedit.utf16.distance(from: start, to: end)), caretPos: caretPos.utf16Offset(in: preedit))
512	        } else {
513	          // Use a full-width space placeholder to prevent iTerm2 from echoing raw preedit;
514	          // half-width placeholders make the Chinese composition baseline unstable.
515	          show(preedit: preedit.isEmpty ? "" : "　", selRange: NSRange(location: 0, length: 0), caretPos: 0)
516	        }
517	      }
518	
519	      let numCandidates = Int(ctx.menu.num_candidates)
520	      var candidates = [String]()
521	      var comments = [String]()
522	      for i in 0..<numCandidates {
523	        let candidate = ctx.menu.candidates[i]
524	        candidates.append(candidate.text.map { String(cString: $0) } ?? "")
525	        comments.append(candidate.comment.map { String(cString: $0) } ?? "")
526	      }
527	      var labels = [String]()
528	      // swiftlint:disable identifier_name
529	      if let select_keys = ctx.menu.select_keys {
530	        labels = String(cString: select_keys).map { String($0) }
531	      } else if let select_labels = ctx.select_labels {
532	        let pageSize = Int(ctx.menu.page_size)
533	        for i in 0..<pageSize {
534	          labels.append(select_labels[i].map { String(cString: $0) } ?? "")
535	        }
536	      }
537	      // swiftlint:enable identifier_name
538	      let page = Int(ctx.menu.page_no)
539	      let lastPage = ctx.menu.is_last_page
540	
541	      let selRange = NSRange(location: start.utf16Offset(in: preedit), length: preedit.utf16.distance(from: start, to: end))
542	      showPanel(preedit: inlinePreedit ? "" : preedit, selRange: selRange, caretPos: caretPos.utf16Offset(in: preedit),
543	                candidates: candidates, comments: comments, labels: labels, highlighted: Int(ctx.menu.highlighted_candidate_index),
544	                page: page, lastPage: lastPage)
545	      _ = rimeAPI.free_context(&ctx)
546	    } else {
547	      hidePalettes()
548	    }
549	  }
550	
551	  func commit(string: String) {
552	    guard let client = client else { return }
553	    client.insertText(string, replacementRange: .empty)
554	    preedit = ""
555	    hidePalettes()
556	  }
557	
558	  func show(preedit: String, selRange: NSRange, caretPos: Int) {
559	    guard let client = client else { return }
560	    if self.preedit == preedit && self.caretPos == caretPos && self.selRange == selRange {
561	      return
562	    }
563	
564	    self.preedit = preedit
565	    self.caretPos = caretPos
566	    self.selRange = selRange
567	
568	    let start = selRange.location
569	    let attrString = NSMutableAttributedString(string: preedit)
570	    if start > 0 {
571	      let attrs = mark(forStyle: kTSMHiliteConvertedText, at: NSRange(location: 0, length: start))! as! [NSAttributedString.Key: Any]
572	      attrString.setAttributes(attrs, range: NSRange(location: 0, length: start))
573	    }
574	    let remainingRange = NSRange(location: start, length: preedit.utf16.count - start)
575	    let attrs = mark(forStyle: kTSMHiliteSelectedRawText, at: remainingRange)! as! [NSAttributedString.Key: Any]
576	    attrString.setAttributes(attrs, range: remainingRange)
577	    client.setMarkedText(attrString, selectionRange: NSRange(location: caretPos, length: 0), replacementRange: .empty)
578	  }
579	
580	  // swiftlint:disable:next function_parameter_count
581	  func showPanel(preedit: String, selRange: NSRange, caretPos: Int, candidates: [String], comments: [String], labels: [String], highlighted: Int, page: Int, lastPage: Bool) {
582	    guard let client = client else { return }
583	    var inputPos = NSRect()
584	    client.attributes(forCharacterIndex: 0, lineHeightRectangle: &inputPos)
585	    if let panel = NSApp.squirrelAppDelegate.panel {
586	      panel.position = inputPos
587	      panel.inputController = self
588	      panel.update(preedit: preedit, selRange: selRange, caretPos: caretPos, candidates: candidates, comments: comments, labels: labels,
589	                   highlighted: highlighted, page: page, lastPage: lastPage, update: true)
590	    }
591	  }
592	
593	  private func handleASCIIModeToggle(_ notification: Notification) {
594	    guard let enableASCII = notification.object as? Bool else { return }
595	    guard session != 0 && rimeAPI.find_session(session) else { return }
596	
597	    rimeAPI.set_option(session, "ascii_mode", enableASCII)
598	    rimeUpdate()
599	  }
600	
601	  private func reportASCIIMode(_: Notification) {
602	    guard client != nil else { return }
603	    guard session != 0 && rimeAPI.find_session(session) else { return }
604	
605	    let isASCIIMode = rimeAPI.get_option(session, "ascii_mode")
606	    let status = isASCIIMode ? "ascii" : "nascii"
607	
608	    DistributedNotificationCenter.default().postNotificationName(
609	      .init("SquirrelASCIIModeResponse"),
610	      object: status
611	    )
612	  }
613	
614	}
